import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.CQYuu_FX.js";const _=JSON.parse('{"title":"注文管理","description":"","frontmatter":{"title":"注文管理"},"headers":[],"relativePath":"tenant/06-orders.md","filePath":"tenant/06-orders.md"}'),o={name:"tenant/06-orders.md"};function l(h,t,i,n,s,b){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="_6-注文管理" tabindex="-1">6. 注文管理 <a class="header-anchor" href="#_6-注文管理" aria-label="Permalink to &quot;6. 注文管理&quot;">​</a></h1><p>注文管理では、セルフオーダー、ハンディPOS、テイクアウトなどから入った注文を確認します。注文内容はKDS、レジ、レポートに連動します。</p><h2 id="注文の入口" tabindex="-1">注文の入口 <a class="header-anchor" href="#注文の入口" aria-label="Permalink to &quot;注文の入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注文方法</th><th>主な利用場面</th></tr></thead><tbody><tr><td>セルフオーダー</td><td>お客様がテーブルQRから注文</td></tr><tr><td>ハンディPOS</td><td>スタッフがお客様の代わりに注文入力</td></tr><tr><td>テイクアウト</td><td>店外・事前注文の受付</td></tr><tr><td>予約連動</td><td>予約来店後の着席・注文管理</td></tr></tbody></table><h2 id="ハンディposで注文する" tabindex="-1">ハンディPOSで注文する <a class="header-anchor" href="#ハンディposで注文する" aria-label="Permalink to &quot;ハンディPOSで注文する&quot;">​</a></h2><ol><li>ハンディPOSを開きます。</li><li>店舗とテーブルを確認します。</li><li>商品を選び、数量とオプションを確認します。</li><li>注文内容を送信します。</li><li>KDSに注文が表示されることを確認します。</li></ol><h2 id="注文履歴を確認する" tabindex="-1">注文履歴を確認する <a class="header-anchor" href="#注文履歴を確認する" aria-label="Permalink to &quot;注文履歴を確認する&quot;">​</a></h2><p>注文履歴では、注文時刻、テーブル、商品、数量、ステータスを確認できます。問い合わせや会計確認の際に利用してください。</p><h2 id="注文の変更・取消" tabindex="-1">注文の変更・取消 <a class="header-anchor" href="#注文の変更・取消" aria-label="Permalink to &quot;注文の変更・取消&quot;">​</a></h2><p>注文送信後の変更は、厨房での調理状況や店舗ルールに合わせて行ってください。すでに調理済みの商品を取り消す場合は、会計・在庫・オペレーションへの影響を確認してください。</p><h2 id="ステータスの考え方" tabindex="-1">ステータスの考え方 <a class="header-anchor" href="#ステータスの考え方" aria-label="Permalink to &quot;ステータスの考え方&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ステータス</th><th>意味</th></tr></thead><tbody><tr><td>受付済み</td><td>注文が登録された状態</td></tr><tr><td>調理中</td><td>厨房で対応中の状態</td></tr><tr><td>提供済み</td><td>商品提供が完了した状態</td></tr><tr><td>会計済み</td><td>会計が完了した状態</td></tr></tbody></table><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>KDSに注文が出ない</td><td>店舗選択、ネットワーク、KDS画面の更新を確認してください。</td></tr><tr><td>注文内容が違う</td><td>注文履歴とレシート内容を確認してください。</td></tr><tr><td>送信に失敗する</td><td>Wi-Fi接続を確認し、再送信してください。</td></tr><tr><td>テーブルが見つからない</td><td>テーブル管理で登録状態を確認してください。</td></tr></tbody></table>',14)])])}const p=a(o,[["render",l]]);export{_ as __pageData,p as default};
